def get_es_client():
    """Create and return an Elasticsearch client with connection pooling."""
    es_config = {
        'hosts': [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
        'max_retries': 3,
        'retry_on_timeout': True,
        'request_timeout': 10,
        'maxsize': 25,  # Connection pool size for high traffic
    }

    if ES_USER and ES_PASSWORD:
        es_config['basic_auth'] = (ES_USER, ES_PASSWORD)

    return Elasticsearch(**es_config)


# Initialize ES client at module level for connection reuse
es_client = get_es_client()


def build_search_query(keyword, category=None, min_price=None, max_price=None,
                       sort_by=None, sort_order='desc'):
    """Build an Elasticsearch query with multi-match, filters, and boosting."""
    must_clauses = []
    filter_clauses = []

    # Multi-match query across multiple fields with boosting
    if keyword:
        must_clauses.append({
            'multi_match': {
                'query': keyword,
                'fields': [
                    'name^3',        # Product name has highest boost
                    'name.ngram^1',  # Partial matches on name
                    'description^1.5',
                    'brand^2',
                    'category^1.5',
                    'tags^1',
                    'sku^2'
                ],
                'type': 'best_fields',
                'fuzziness': 'AUTO',
                'prefix_length': 2,
                'minimum_should_match': '75%'
            }
        })

    # Category filter
    if category:
        filter_clauses.append({
            'term': {'category.keyword': category}
        })

    # Price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range['gte'] = float(min_price)
        if max_price is not None:
            price_range['lte'] = float(max_price)
        filter_clauses.append({
            'range': {'price': price_range}
        })

    # Only return in-stock products by default
    filter_clauses.append({
        'term': {'in_stock': True}
    })

    query = {
        'bool': {
            'must': must_clauses if must_clauses else [{'match_all': {}}],
            'filter': filter_clauses
        }
    }

    # Function score to boost by popularity/sales
    search_body = {
        'query': {
            'function_score': {
                'query': query,
                'functions': [
                    {
                        'field_value_factor': {
                            'field': 'popularity_score',
                            'factor': 1.2,
                            'modifier': 'log1p',
                            'missing': 1
                        }
                    },
                    {
                        'field_value_factor': {
                            'field': 'sales_count',
                            'factor': 0.5,
                            'modifier': 'log1p',
                            'missing': 0
                        }
                    }
                ],
                'score_mode': 'sum',
                'boost_mode': 'multiply'
            }
        }
    }

    # Sorting
    if sort_by:
        sort_mapping = {
            'price': 'price',
            'name': 'name.keyword',
            'rating': 'average_rating',
            'newest': 'created_at',
            'popularity': 'popularity_score',
        }
        sort_field = sort_mapping.get(sort_by)
        if sort_field:
            search_body['sort'] = [
                {sort_field: {'order': sort_order}},
                '_score'
            ]

    # Aggregations for faceted search
    search_body['aggs'] = {
        'categories': {
            'terms': {
                'field': 'category.keyword',
                'size': 20
            }
        },
        'brands': {
            'terms': {
                'field': 'brand.keyword',
                'size': 20
            }
        },
        'price_ranges': {
            'range': {
                'field': 'price',
                'ranges': [
                    {'key': 'under_25', 'to': 25},
                    {'key': '25_to_50', 'from': 25, 'to': 50},
                    {'key': '50_to_100', 'from': 50, 'to': 100},
                    {'key': '100_to_200', 'from': 100, 'to': 200},
                    {'key': 'over_200', 'from': 200}
                ]
            }
        },
        'avg_price': {
            'avg': {'field': 'price'}
        }
    }

    # Highlight matching text
    search_body['highlight'] = {
        'fields': {
            'name': {'number_of_fragments': 1},
            'description': {'number_of_fragments': 2, 'fragment_size': 150}
        },
        'pre_tags': ['<em>'],
        'post_tags': ['</em>']
    }

    # Suggest for typo correction
    if keyword:
        search_body['suggest'] = {
            'text': keyword,
            'name_suggestion': {
                'phrase': {
                    'field': 'name.trigram',
                    'size': 3,
                    'gram_size': 3,
                    'direct_generator': [{
                        'field': 'name.trigram',
                        'suggest_mode': 'popular'
                    }]
                }
            }
        }

    return search_body


def format_search_results(es_response, page, page_size):
    """Format Elasticsearch response into a clean API response."""
    hits = es_response.get('hits', {})
    total = hits.get('total', {})
    total_count = total.get('value', 0) if isinstance(total, dict) else total

    products = []
    for hit in hits.get('hits', []):
        product = hit.get('_source', {})
        product['id'] = hit.get('_id')
        product['_score'] = hit.get('_score')

        # Add highlights if available
        if 'highlight' in hit:
            product['highlights'] = hit['highlight']

        products.append(product)

    # Format aggregations
    aggregations = {}
    raw_aggs = es_response.get('aggregations', {})

    if 'categories' in raw_aggs:
        aggregations['categories'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in raw_aggs['categories'].get('buckets', [])
        ]

    if 'brands' in raw_aggs:
        aggregations['brands'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in raw_aggs['brands'].get('buckets', [])
        ]

    if 'price_ranges' in raw_aggs:
        aggregations['price_ranges'] = [
            {'range': bucket['key'], 'count': bucket['doc_count']}
            for bucket in raw_aggs['price_ranges'].get('buckets', [])
        ]

    if 'avg_price' in raw_aggs:
        aggregations['average_price'] = round(raw_aggs['avg_price'].get('value', 0), 2)

    # Format suggestions
    suggestions = []
    raw_suggest = es_response.get('suggest', {})
    if 'name_suggestion' in raw_suggest:
        for entry in raw_suggest['name_suggestion']:
            for option in entry.get('options', []):
                suggestions.append(option.get('text'))

    total_pages = (total_count + page_size - 1) // page_size if page_size > 0 else 0

    result = {
        'products': products,
        'pagination': {
            'total': total_count,
            'page': page,
            'page_size': page_size,
            'total_pages': total_pages,
            'has_next': page < total_pages,
            'has_prev': page > 1
        },
        'facets': aggregations
    }

    if suggestions:
        result['suggestions'] = suggestions

    return result


@app.route('/api/search', methods=['GET'])
def search_products():
    """
    Search products endpoint.

    Query Parameters:
        q (str): Search keyword (required)
        category (str): Filter by category
        min_price (float): Minimum price filter
        max_price (float): Maximum price filter
        sort_by (str): Sort field (price, name, rating, newest, popularity)
        sort_order (str): Sort order (asc, desc). Default: desc
        page (int): Page number (default: 1)
        page_size (int): Results per page (default: 20, max: 100)

    Returns:
        JSON with products, pagination, facets, and suggestions
    """
    start_time = time.time()

    # Extract and validate query parameters
    keyword = request.args.get('q', '').strip()
    if not keyword:
        return jsonify({
            'error': 'Missing required parameter',
            'message': 'Query parameter "q" is required',
            'status': 400
        }), 400

    if len(keyword) > 200:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'Query parameter "q" must be 200 characters or fewer',
            'status': 400
        }), 400

    category = request.args.get('category', '').strip() or None
    sort_by = request.args.get('sort_by', '').strip() or None
    sort_order = request.args.get('sort_order', 'desc').strip().lower()

    if sort_order not in ('asc', 'desc'):
        sort_order = 'desc'

    if sort_by and sort_by not in ('price', 'name', 'rating', 'newest', 'popularity'):
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'sort_by must be one of: price, name, rating, newest, popularity',
            'status': 400
        }), 400

    # Parse numeric parameters safely
    try:
        page = max(1, int(request.args.get('page', 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        page_size = min(100, max(1, int(request.args.get('page_size', 20))))
    except (ValueError, TypeError):
        page_size = 20

    min_price = None
    max_price = None
    try:
        if 'min_price' in request.args:
            min_price = float(request.args.get('min_price'))
            if min_price < 0:
                return jsonify({
                    'error': 'Invalid parameter',
                    'message': 'min_price must be non-negative',
                    'status': 400
                }), 400
    except (ValueError, TypeError):
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'min_price must be a valid number',
            'status': 400
        }), 400

    try:
        if 'max_price' in request.args:
            max_price = float(request.args.get('max_price'))
            if max_price < 0:
                return jsonify({
                    'error': 'Invalid parameter',
                    'message': 'max_price must be non-negative',
                    'status': 400
                }), 400
    except (ValueError, TypeError):
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'max_price must be a valid number',
            'status': 400
        }), 400

    if min_price is not None and max_price is not None and min_price > max_price:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'min_price cannot be greater than max_price',
            'status': 400
        }), 400

    # Build the search query
    search_body = build_search_query(
        keyword=keyword,
        category=category,
        min_price=min_price,
        max_price=max_price,
        sort_by=sort_by,
        sort_order=sort_order
    )

    # Calculate pagination offset
    from_offset = (page - 1) * page_size

    # Source fields to return (exclude large fields to reduce payload)
    source_fields = [
        'name', 'description', 'price', 'sale_price', 'currency',
        'brand', 'category', 'image_url', 'thumbnail_url',
        'average_rating', 'review_count', 'in_stock', 'sku',
        'tags', 'created_at', 'popularity_score'
    ]

    try:
        es_response = es_client.search(
            index=ES_INDEX,
            body=search_body,
            from_=from_offset,
            size=page_size,
            _source=source_fields,
            request_timeout=5  # Tight timeout for user-facing search
        )
    except Exception as e:
        logger.error(f"Elasticsearch query failed: {str(e)}", exc_info=True)
        return jsonify({
            'error': 'Search service unavailable',
            'message': 'Unable to process search request. Please try again later.',
            'status': 503
        }), 503

    # Format results
    result = format_search_results(es_response, page, page_size)

    # Add metadata
    elapsed_ms = round((time.time() - start_time) * 1000, 2)
    result['meta'] = {
        'query': keyword,
        'response_time_ms': elapsed_ms,
        'filters_applied': {
            'category': category,
            'min_price': min_price,
            'max_price': max_price,
            'sort_by': sort_by,
            'sort_order': sort_order
        }
    }

    logger.info(
        f"Search query='{keyword}' category={category} page={page} "
        f"results={result['pagination']['total']} time={elapsed_ms}ms"
    )

    response = jsonify(result)
    # Cache headers for CDN/reverse proxy caching during high traffic
    response.headers['Cache-Control'] = 'public, max-age=30, stale-while-revalidate=60'
    response.headers['Vary'] = 'Accept-Encoding'

    return response, 200


@app.route('/api/search/suggest', methods=['GET'])
def search_suggestions():
    """
    Autocomplete/suggest endpoint for search-as-you-type.

    Query Parameters:
        q (str): Partial search term

    Returns:
        JSON with suggestion list
    """
    keyword = request.args.get('q', '').strip()
    if not keyword or len(keyword) < 2:
        return jsonify({'suggestions': []}), 200

    try:
        search_body = {
            'suggest': {
                'product_suggest': {
                    'prefix': keyword,
                    'completion': {
                        'field': 'name_suggest',
                        'size': 10,
                        'skip_duplicates': True,
                        'fuzzy': {
                            'fuzziness': 'AUTO'
                        }
                    }
                }
            },
            '_source': ['name', 'category', 'brand', 'image_url', 'price']
        }

        es_response = es_client.search(
            index=ES_INDEX,
            body=search_body,
            request_timeout=3
        )

        suggestions = []
        suggest_results = es_response.get('suggest', {}).get('product_suggest', [])
        for entry in suggest_results:
            for option in entry.get('options', []):
                source = option.get('_source', {})
                suggestions.append({
                    'text': option.get('text'),
                    'name': source.get('name'),
                    'category': source.get('category'),
                    'brand': source.get('brand'),
                    'price': source.get('price'),
                    'image_url': source.get('image_url')
                })

        response = jsonify({'suggestions': suggestions})
        response.headers['Cache-Control'] = 'public, max-age=60'
        return response, 200

    except Exception as e:
        logger.error(f"Suggestion query failed: {str(e)}", exc_info=True)
        return jsonify({'suggestions': []}), 200


@app.route('/api/search/health', methods=['GET'])
def health_check():
    """Health check endpoint for load balancers."""
    try:
        info = es_client.info(request_timeout=2)
        cluster_health = es_client.cluster.health(request_timeout=2)
        return jsonify({
            'status': 'healthy',
            'elasticsearch': {
                'cluster_name': info.get('cluster_name'),
                'status': cluster_health.get('status'),
                'number_of_nodes': cluster_health.get('number_of_nodes')
            }
        }), 200
    except Exception as e:
        logger.error(f"Health check failed: {str(e)}")
        return jsonify({
            'status': 'unhealthy',
            'error': str(e)
        }), 503


