def create_index_mapping():
    """Create the products index with optimized mappings if it doesn't exist."""
    if es_client.indices.exists(index=ES_INDEX):
        logger.info(f"Index '{ES_INDEX}' already exists")
        return

    mapping = {
        'settings': {
            'number_of_shards': 3,
            'number_of_replicas': 1,
            'refresh_interval': '1s',
            'analysis': {
                'analyzer': {
                    'ngram_analyzer': {
                        'type': 'custom',
                        'tokenizer': 'standard',
                        'filter': ['lowercase', 'ngram_filter']
                    },
                    'trigram_analyzer': {
                        'type': 'custom',
                        'tokenizer': 'standard',
                        'filter': ['lowercase', 'shingle_filter']
                    }
                },
                'filter': {
                    'ngram_filter': {
                        'type': 'ngram',
                        'min_gram': 3,
                        'max_gram': 4
                    },
                    'shingle_filter': {
                        'type': 'shingle',
                        'min_shingle_size': 2,
                        'max_shingle_size': 3
                    }
                }
            }
        },
        'mappings': {
            'properties': {
                'name': {
                    'type': 'text',
                    'analyzer': 'standard',
                    'fields': {
                        'keyword': {'type': 'keyword'},
                        'ngram': {
                            'type': 'text',
                            'analyzer': 'ngram_analyzer'
                        },
                        'trigram': {
                            'type': 'text',
                            'analyzer': 'trigram_analyzer'
                        }
                    }
                },
                'name_suggest': {
                    'type': 'completion',
                    'analyzer': 'standard'
                },
                'description': {
                    'type': 'text',
                    'analyzer': 'standard'
                },
                'price': {'type': 'float'},
                'sale_price': {'type': 'float'},
                'currency': {'type': 'keyword'},
                'brand': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'category': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'tags': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'sku': {'type': 'keyword'},
                'image_url': {'type': 'keyword', 'index': False},
                'thumbnail_url': {'type': 'keyword', 'index': False},
                'average_rating': {'type': 'float'},
                'review_count': {'type': 'integer'},
                'in_stock': {'type': 'boolean'},
                'popularity_score': {'type': 'float'},
                'sales_count': {'type': 'integer'},
                'created_at': {'type': 'date'}
            }
        }
    }

    es_client.indices.create(index=ES_INDEX, body=mapping)
    logger.info(f"Created index '{ES_INDEX}' with mappings")


